import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.util.HtmlUtils;
import java.util.List;
import java.util.stream.Collectors;

@Controller
@RequestMapping("/comments")
public class CommentController {

    @Autowired
    private CommentService commentService;

    @GetMapping
    public String displayComments(Model model) {
        List<Comment> comments = commentService.getAllComments();
        List<CommentDTO> sanitizedComments = comments.stream()
                .map(this::sanitizeComment)
                .collect(Collectors.toList());
        model.addAttribute("comments", sanitizedComments);
        return "comments";
    }

    private CommentDTO sanitizeComment(Comment comment) {
        CommentDTO dto = new CommentDTO();
        dto.setId(comment.getId());
        dto.setUsername(HtmlUtils.htmlEscape(comment.getUsername()));
        dto.setContent(sanitizeHtmlContent(comment.getContent()));
        dto.setCreatedAt(comment.getCreatedAt());
        return dto;
    }

    private String sanitizeHtmlContent(String content) {
        if (content == null) {
            return "";
        }
        
        String escaped = HtmlUtils.htmlEscape(content);
        
        escaped = escaped.replace("&lt;b&gt;", "<b>")
                        .replace("&lt;/b&gt;", "</b>")
                        .replace("&lt;i&gt;", "<i>")
                        .replace("&lt;/i&gt;", "</i>")
                        .replace("&lt;u&gt;", "<u>")
                        .replace("&lt;/u&gt;", "</u>")
                        .replace("&lt;br&gt;", "<br>")
                        .replace("&lt;br/&gt;", "<br/>")
                        .replace("&lt;br /&gt;", "<br />");
        
        return escaped;
    }
}